# Dashboard Blueprint\nfrom flask import Blueprint, request\nfrom flask_jwt_extended import jwt_required, get_jwt_identity\nfrom flask_app.models import (\n    db, StokRealTime, OpnameSession, Notifikasi, StokMutasi,\n    Produk, Outlet, User\n)\nfrom flask_app.utils.helpers import ResponseHelper, QueryHelper\nfrom datetime import datetime, date, timedelta\nfrom sqlalchemy import func, and_\nimport logging\n\ndashboard_bp = Blueprint('dashboard', __name__)\nlogger = logging.getLogger(__name__)\n\n@dashboard_bp.route('/opname-stats', methods=['GET'])\n@jwt_required()\ndef get_opname_stats():\n    \"\"\"Dashboard stats khusus untuk Stok Opname\"\"\"\n    try:\n        outlet_id = request.args.get('outlet_id', type=int)\n        \n        if not outlet_id:\n            return ResponseHelper.error('outlet_id required', status_code=400)\n        \n        # Total stok barang\n        total_produk = db.session.query(func.count(StokRealTime.id)).filter(\n            StokRealTime.outlet_id == outlet_id\n        ).scalar() or 0\n        \n        total_qty = db.session.query(func.sum(StokRealTime.qty_stok)).filter(\n            StokRealTime.outlet_id == outlet_id\n        ).scalar() or 0\n        \n        # Total barang\n        barang_items = db.session.query(func.count(StokRealTime.id)).filter(\n            StokRealTime.outlet_id == outlet_id\n        ).scalar() or 0\n        \n        # Rak penuh (stats)\n        from flask_app.models import Rak, LokasiBarang\n        rak_penuh = 0\n        raks = Rak.query.filter_by(outlet_id=outlet_id).all()\n        for rak in raks:\n            total_qty_rak = db.session.query(func.sum(LokasiBarang.qty_di_rak)).filter(\n                LokasiBarang.rak_id == rak.id\n            ).scalar() or 0\n            if total_qty_rak >= rak.kapasitas_maksimum:\n                rak_penuh += 1\n        \n        # Barang minimum stok\n        item_minimum = db.session.query(func.count(StokRealTime.id)).filter(\n            and_(\n                StokRealTime.outlet_id == outlet_id,\n                StokRealTime.status_stok.in_(['minimum', 'habis'])\n            )\n        ).scalar() or 0\n        \n        # Barang paling cepat keluar (top 5)\n        today = date.today()\n        week_ago = today - timedelta(days=7)\n        \n        top_products = db.session.query(\n            Produk.id,\n            Produk.kode_barang,\n            Produk.nama_barang,\n            func.sum(StokMutasi.qty).label('total_keluar')\n        ).join(\n            StokMutasi,\n            and_(\n                StokMutasi.produk_id == Produk.id,\n                StokMutasi.outlet_id == outlet_id,\n                StokMutasi.tipe_mutasi == 'barang_keluar',\n                StokMutasi.tanggal_mutasi >= week_ago\n            )\n        ).group_by(\n            Produk.id, Produk.kode_barang, Produk.nama_barang\n        ).order_by(\n            func.sum(StokMutasi.qty).desc()\n        ).limit(5).all()\n        \n        top_products_data = [{\n            'kode_barang': p[1],\n            'nama_barang': p[2],\n            'total_keluar': int(p[3]) if p[3] else 0\n        } for p in top_products]\n        \n        # Histori transaksi terbaru\n        recent_transactions = db.session.query(\n            StokMutasi.tipe_mutasi,\n            Produk.nama_barang,\n            StokMutasi.qty,\n            User.nama_lengkap,\n            StokMutasi.created_at\n        ).join(Produk).join(User).filter(\n            StokMutasi.outlet_id == outlet_id\n        ).order_by(\n            StokMutasi.created_at.desc()\n        ).limit(10).all()\n        \n        recent_data = [{\n            'tipe': str(t[0].value),\n            'produk': t[1],\n            'qty': t[2],\n            'user': t[3],\n            'waktu': t[4].isoformat()\n        } for t in recent_transactions]\n        \n        # Statistik barang masuk dan keluar\n        today = date.today()\n        \n        masuk_today = db.session.query(func.sum(StokMutasi.qty)).filter(\n            and_(\n                StokMutasi.outlet_id == outlet_id,\n                StokMutasi.tipe_mutasi == 'barang_masuk',\n                StokMutasi.tanggal_mutasi == today\n            )\n        ).scalar() or 0\n        \n        keluar_today = db.session.query(func.sum(StokMutasi.qty)).filter(\n            and_(\n                StokMutasi.outlet_id == outlet_id,\n                StokMutasi.tipe_mutasi == 'barang_keluar',\n                StokMutasi.tanggal_mutasi == today\n            )\n        ).scalar() or 0\n        \n        # Grafik aktivitas stok (7 hari terakhir)\n        activity_data = []\n        for i in range(6, -1, -1):\n            day = today - timedelta(days=i)\n            \n            masuk = db.session.query(func.sum(StokMutasi.qty)).filter(\n                and_(\n                    StokMutasi.outlet_id == outlet_id,\n                    StokMutasi.tipe_mutasi == 'barang_masuk',\n                    StokMutasi.tanggal_mutasi == day\n                )\n            ).scalar() or 0\n            \n            keluar = db.session.query(func.sum(StokMutasi.qty)).filter(\n                and_(\n                    StokMutasi.outlet_id == outlet_id,\n                    StokMutasi.tipe_mutasi == 'barang_keluar',\n                    StokMutasi.tanggal_mutasi == day\n                )\n            ).scalar() or 0\n            \n            activity_data.append({\n                'tanggal': day.isoformat(),\n                'masuk': int(masuk),\n                'keluar': int(keluar)\n            })\n        \n        data = {\n            'total_stok_barang': int(total_qty) if total_qty else 0,\n            'total_barang': barang_items,\n            'rak_penuh': rak_penuh,\n            'barang_minimum_stok': item_minimum,\n            'barang_paling_cepat_keluar': top_products_data,\n            'histori_transaksi_terbaru': recent_data,\n            'statistik_harian': {\n                'barang_masuk_hari_ini': int(masuk_today),\n                'barang_keluar_hari_ini': int(keluar_today)\n            },\n            'grafik_aktivitas_stok_7hari': activity_data\n        }\n        \n        return ResponseHelper.success(data)\n    \n    except Exception as e:\n        logger.error(f'Get opname stats error: {str(e)}')\n        return ResponseHelper.error(str(e), status_code=500)\n\n@dashboard_bp.route('/notifications', methods=['GET'])\n@jwt_required()\ndef get_notifications():\n    \"\"\"Get unread notifications untuk current user\"\"\"\n    try:\n        user_id = get_jwt_identity()\n        \n        limit = request.args.get('limit', 20, type=int)\n        \n        notifications = Notifikasi.query.filter_by(\n            user_id=user_id,\n            is_read=False\n        ).order_by(\n            Notifikasi.created_at.desc()\n        ).limit(limit).all()\n        \n        data = [{\n            'id': n.id,\n            'tipe': n.tipe_notifikasi,\n            'pesan': n.pesan,\n            'severity': n.severity,\n            'action_url': n.action_url,\n            'created_at': n.created_at.isoformat()\n        } for n in notifications]\n        \n        return ResponseHelper.success({\n            'notifications': data,\n            'unread_count': len(notifications)\n        })\n    \n    except Exception as e:\n        logger.error(f'Get notifications error: {str(e)}')\n        return ResponseHelper.error(str(e), status_code=500)\n\n@dashboard_bp.route('/notification/<int:notif_id>/mark-read', methods=['POST'])\n@jwt_required()\ndef mark_notification_read(notif_id):\n    \"\"\"Mark notification as read\"\"\"\n    try:\n        notif = Notifikasi.query.get(notif_id)\n        \n        if not notif:\n            return ResponseHelper.error('Notification not found', status_code=404)\n        \n        notif.is_read = True\n        notif.read_at = datetime.utcnow()\n        db.session.commit()\n        \n        return ResponseHelper.success(None, 'Notification marked as read')\n    \n    except Exception as e:\n        logger.error(f'Mark notification read error: {str(e)}')\n        db.session.rollback()\n        return ResponseHelper.error(str(e), status_code=500)\n"
